pred_cypher:
WITH [ 
  { ocean: 'Pacific Ocean', avg_depth: (SELECT avg_vertical_depth_m FROM Ocean WHERE name = 'Pacific Ocean') }, 
  { ocean: 'Indian Ocean', avg_depth: (SELECT avg_vertical_depth_m FROM Ocean WHERE name = 'Indian Ocean') } 
] AS oceans 
RETURN (oceans[0].avg_depth - oceans[1].avg_depth) AS depth_difference
